using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using System.Text.RegularExpressions;
using YourNamespace.Models;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;

        public ProductController()
        {
            _context = new ApplicationDbContext();
        }

        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .Select(r => new ReviewViewModel
                {
                    UserName = r.UserName,
                    Content = SanitizeReviewContent(r.Content),
                    CreatedAt = r.CreatedAt
                })
                .ToList();

            return View(reviews);
        }

        private string SanitizeReviewContent(string content)
        {
            if (string.IsNullOrEmpty(content))
                return string.Empty;

            // Allow basic formatting tags <b> and <i>
            string sanitizedContent = Regex.Replace(content, @"<(?!\/?(b|i)\b)[^>]*>", string.Empty);

            return sanitizedContent;
        }
    }
}

// Razor View (Reviews.cshtml)
@model IEnumerable<YourNamespace.Models.ReviewViewModel>

@foreach (var review in Model)
{
    <div class="review">
        <h4>@Html.Encode(review.UserName)</h4>
        <p>@Html.Raw(review.Content)</p>
        <small>@Html.Encode(review.CreatedAt.ToString("g"))</small>
    </div>
}